UPDATE bus_schedule_search
depart_time = #{departTime}, line_id = #{lineId}, start_city = #{startCity}, end_city = #{endCity}, duration = #{duration}, arrive_time = #{arriveTime}, price = #{price}, seat_remaining = #{seatRemaining}, status = #{status}
WHERE schedule_id = #{scheduleId}

UPDATE bus_schedule_search
SET seat_remaining = #{seatRemaining}
WHERE schedule_id = #{scheduleId}

UPDATE bus_schedule_search
SET seat_remaining = seat_remaining - #{ticketCount}
WHERE schedule_id = #{scheduleId}
AND seat_remaining >= #{ticketCount}

UPDATE bus_schedule_search
SET seat_remaining = seat_remaining + #{ticketCount}
WHERE schedule_id = #{scheduleId}

UPDATE bus_schedule_search
SET price = #{price}
WHERE schedule_id = #{scheduleId}

UPDATE bus_schedule_search
SET status = #{status}
WHERE schedule_id = #{scheduleId}

